import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { FC, ReactNode } from 'react';
import { classNames } from '../../../../helpers/classnames';
import { Icon } from '../../../Icon';
import { Progress } from '../../../Progress';
import { Typography } from '../../../Typography';
import { FileUploaderListItemAction, FileUploaderListItemProps } from './FileUploaderListItem.types';
import './FileUploaderListItem.scss';
import { mapFileIcon } from './helper';

export const FileUploaderListItem: FC<FileUploaderListItemProps> = ({
	name,
	state = 'upload',
	onRefresh,
	onRemove,
	iconName,
	id,
	type,
	className,
	helperText,
	percent,
	size,
	loaded,
	actions,
	...props
}) => {
	const handleRefresh = (): void => {
		onRefresh?.({ id, name, state, iconName, type });
	};

	const handleRemove = (): void => {
		onRemove?.({ id, name, state, iconName, type });
	};

	const fileIcon = mapFileIcon(type) as React.ReactElement;

	const actionsViews = (actions, state): ReactNode => {
		if (React.isValidElement(actions)) {
			return actions;
		}
		return actions.map(
			(fileAction: FileUploaderListItemAction) =>
				(!fileAction.showStatuses || fileAction.showStatuses.includes(state)) && (
					<span className="dsb_file-uploader-file-delete">
						<Icon
							iconName={fileAction.icon}
							size="large"
							onClick={() =>
								fileAction.onClick({
									id,
									name,
									state,
									iconName,
									type,
								})
							}
						/>
					</span>
				),
		);
	};

	const defaultActions = actions ? (
		actionsViews(actions, state)
	) : (
		<>
			{state === 'error' && (
				<span className="dsb_file-uploader-file-refresh">
					<Icon iconName={Icons.Refresh} size="large" onClick={handleRefresh} />
				</span>
			)}
			<span className="dsb_file-uploader-file-delete">
				<Icon iconName={Icons.Close} size="large" onClick={handleRemove} />
			</span>
		</>
	);

	return (
		<div className="dsb_file-uploader_file" role="listitem">
			<div
				data-testid="FileUploaderListItem"
				className={classNames('dsb_file-uploader-file-description', className)}
				{...props}
			>
				<div className="dsb_file-uploader-file_name-wrapper">
					<span className="dsb_file-uploader-file_name">
						<span className="dsb_file-uploader-file-icon">{fileIcon}</span>
						<Typography variant="body2" className="dsb_file-uploader-file_name-text">
							{name}
							{helperText && <span className={classNames(state === 'error' && 'error-text')}>{helperText}</span>}
						</Typography>
					</span>
				</div>
				{defaultActions}
			</div>
			<div className="dsb_file-uploader-file-progress">
				{state === 'process' && (
					<Progress className="progress-style" cycled={!!percent} value={percent ? percent : 0}></Progress>
				)}
				{percent && (
					<div className="size-line">
						<span>
							{size} из {loaded}
						</span>
						<span className="percent">{percent}%</span>
					</div>
				)}
			</div>
		</div>
	);
};
